window.KJV1769_STRONG_BOOKS["Amos"] = {"osis":"Amos","book":"아모스","verses":{"1:1":{"text":"The words of Amos, who was among the herdmen of Tekoa, which he saw concerning Israel in the days of Uzziah king of Judah, and in the days of Jeroboam the son of Joash king of Israel, two years before the earthquake.","words":[["H1697","The words",0,9],["H5986","of Amos",10,17],["H5349","who was among the herdmen",19,44],["H8620","of Tekoa",45,53],["H2372","which he saw",55,67],["H3478","concerning Israel",68,85],["H3117","in the days",86,97],["H5818","of Uzziah",98,107],["H4428","king",108,112],["H3063","of Judah",113,121],["H3117","and in the days",123,138],["H3379","of Jeroboam",139,150],["H1121","the son",151,158],["H3101","of Joash",159,167],["H4428","king",168,172],["H3478","of Israel",173,182],["H8141","two years",184,193],["H6440","before",194,200],["H7494","the earthquake",201,215]]},"1:2":{"text":"And he said, The LORD will roar from Zion, and utter his voice from Jerusalem; and the habitations of the shepherds shall mourn, and the top of Carmel shall wither.","words":[["H0559","And he said",0,11],["H3068","The LORD",13,21],["H7580","will roar",22,31],["H6726","from Zion",32,41],["H5414","and utter",43,52],["H6963","his voice",53,62],["H3389","from Jerusalem",63,77],["H4999","and the habitations",79,98],["H7462","of the shepherds",99,115],["H0056","shall mourn",116,127],["H7218","and the top",129,140],["H3760","of Carmel",141,150],["H3001","shall wither",151,163]]},"1:3":{"text":"Thus saith the LORD; For three transgressions of Damascus, and for four, I will not turn away the punishment thereof; because they have threshed Gilead with threshing instruments of iron:","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H7969","For three",21,30],["H6588","transgressions",31,45],["H1834","of Damascus",46,57],["H0702","and for four",59,71],["H7725","I will not turn away",73,93],["H1758","the punishment thereof; because they have threshed",94,144],["H1568","Gilead",145,151],["H2742","with threshing instruments",152,178],["H1270","of iron",179,186]]},"1:4":{"text":"But I will send a fire into the house of Hazael, which shall devour the palaces of Benhadad.","words":[["H7971","But I will send",0,15],["H0784","a fire",16,22],["H1004","into the house",23,37],["H2371","of Hazael",38,47],["H0398","which shall devour",49,67],["H0759","the palaces",68,79],["H1130","of Benhadad",80,91]]},"1:5":{"text":"I will break also the bar of Damascus, and cut off the inhabitant from the plain of Aven, and him that holdeth the sceptre from the house of Eden: and the people of Syria shall go into captivity unto Kir, saith the LORD.","words":[["H7665","I will break",0,12],["H1280","also the bar",13,25],["H1834","of Damascus",26,37],["H3772","and cut off",39,50],["H3427","the inhabitant",51,65],["H1237","from the plain",66,80],["H0206","of Aven",81,88],["H8551","and him that holdeth",90,110],["H7626","the sceptre",111,122],["H1004","from the house",123,137],["H5731","of Eden",138,145],["H1040","of Eden",138,145],["H5971","and the people",147,161],["H0758","of Syria",162,170],["H1540","shall go into captivity",171,194],["H7024","unto Kir",195,203],["H0559","saith",205,210],["H3068","the LORD",211,219]]},"1:6":{"text":"Thus saith the LORD; For three transgressions of Gaza, and for four, I will not turn away the punishment thereof; because they carried away captive the whole captivity, to deliver them up to Edom:","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H7969","For three",21,30],["H6588","transgressions",31,45],["H5804","of Gaza",46,53],["H0702","and for four",55,67],["H7725","I will not turn away",69,89],["H1540","the punishment thereof; because they carried away captive",90,147],["H8003","the whole",148,157],["H1546","captivity",158,167],["H5462","to deliver them up",169,187],["H0123","to Edom",188,195]]},"1:7":{"text":"But I will send a fire on the wall of Gaza, which shall devour the palaces thereof:","words":[["H7971","But I will send",0,15],["H0784","a fire",16,22],["H2346","on the wall",23,34],["H5804","of Gaza",35,42],["H0398","which shall devour",44,62],["H0759","the palaces",63,74]]},"1:8":{"text":"And I will cut off the inhabitant from Ashdod, and him that holdeth the sceptre from Ashkelon, and I will turn mine hand against Ekron: and the remnant of the Philistines shall perish, saith the Lord GOD.","words":[["H3772","And I will cut off",0,18],["H3427","the inhabitant",19,33],["H0795","from Ashdod",34,45],["H8551","and him that holdeth",47,67],["H7626","the sceptre",68,79],["H0831","from Ashkelon",80,93],["H7725","and I will turn",95,110],["H3027","mine hand",111,120],["H6138","against Ekron",121,134],["H7611","and the remnant",136,151],["H6430","of the Philistines",152,170],["H0006","shall perish",171,183],["H0559","saith",185,190],["H0136","the Lord",191,199],["H3069","GOD",200,203]]},"1:9":{"text":"Thus saith the LORD; For three transgressions of Tyrus, and for four, I will not turn away the punishment thereof; because they delivered up the whole captivity to Edom, and remembered not the brotherly covenant:","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H7969","For three",21,30],["H6588","transgressions",31,45],["H6865","of Tyrus",46,54],["H0702","and for four",56,68],["H7725","I will not turn away",70,90],["H5462","the punishment thereof; because they delivered up",91,140],["H8003","the whole",141,150],["H1546","captivity",151,160],["H0123","to Edom",161,168],["H2142","and remembered",170,184],["H0251","not the brotherly",185,202],["H1285","covenant",203,211]]},"1:10":{"text":"But I will send a fire on the wall of Tyrus, which shall devour the palaces thereof.","words":[["H7971","But I will send",0,15],["H0784","a fire",16,22],["H2346","on the wall",23,34],["H6865","of Tyrus",35,43],["H0398","which shall devour",45,63],["H0759","the palaces",64,75]]},"1:11":{"text":"Thus saith the LORD; For three transgressions of Edom, and for four, I will not turn away the punishment thereof; because he did pursue his brother with the sword, and did cast off all pity, and his anger did tear perpetually, and he kept his wrath for ever:","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H7969","For three",21,30],["H6588","transgressions",31,45],["H0123","of Edom",46,53],["H0702","and for four",55,67],["H7725","I will not turn away",69,89],["H7291","the punishment thereof; because he did pursue",90,135],["H0251","his brother",136,147],["H2719","with the sword",148,162],["H7843","and did cast off",164,180],["H7356","all pity",181,189],["H0639","and his anger",191,204],["H2963","did tear",205,213],["H5703","perpetually",214,225],["H8104","and he kept",227,238],["H5678","his wrath",239,248],["H5331","for ever",249,257]]},"1:12":{"text":"But I will send a fire upon Teman, which shall devour the palaces of Bozrah.","words":[["H7971","But I will send",0,15],["H0784","a fire",16,22],["H8487","upon Teman",23,33],["H0398","which shall devour",35,53],["H0759","the palaces",54,65],["H1224","of Bozrah",66,75]]},"1:13":{"text":"Thus saith the LORD; For three transgressions of the children of Ammon, and for four, I will not turn away the punishment thereof; because they have ripped up the women with child of Gilead, that they might enlarge their border:","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H7969","For three",21,30],["H6588","transgressions",31,45],["H1121","of the children",46,61],["H5983","of Ammon",62,70],["H0702","and for four",72,84],["H7725","I will not turn away",86,106],["H1234","the punishment thereof; because they have ripped up",107,158],["H2030","the women with child",159,179],["H1568","of Gilead",180,189],["H7337","that they might enlarge",191,214],["H1366","their border",215,227]]},"1:14":{"text":"But I will kindle a fire in the wall of Rabbah, and it shall devour the palaces thereof, with shouting in the day of battle, with a tempest in the day of the whirlwind:","words":[["H3341","But I will kindle",0,17],["H0784","a fire",18,24],["H2346","in the wall",25,36],["H7237","of Rabbah",37,46],["H0398","and it shall devour",48,67],["H0759","the palaces",68,79],["H8643","thereof, with shouting",80,102],["H3117","in the day",103,113],["H4421","of battle",114,123],["H5591","with a tempest",125,139],["H3117","in the day",140,150],["H5492","of the whirlwind",151,167]]},"1:15":{"text":"And their king shall go into captivity, he and his princes together, saith the LORD.","words":[["H4428","And their king",0,14],["H1980","shall go",15,23],["H1473","into captivity",24,38],["H8269","he and his princes",40,58],["H3162","together",59,67],["H0559","saith",69,74],["H3068","the LORD",75,83]]},"2:1":{"text":"Thus saith the LORD; For three transgressions of Moab, and for four, I will not turn away the punishment thereof; because he burned the bones of the king of Edom into lime:","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H7969","For three",21,30],["H6588","transgressions",31,45],["H4124","of Moab",46,53],["H0702","and for four",55,67],["H7725","I will not turn away",69,89],["H8313","the punishment thereof; because he burned",90,131],["H6106","the bones",132,141],["H4428","of the king",142,153],["H0123","of Edom",154,161],["H7875","into lime",162,171]]},"2:2":{"text":"But I will send a fire upon Moab, and it shall devour the palaces of Kerioth: and Moab shall die with tumult, with shouting, and with the sound of the trumpet:","words":[["H7971","But I will send",0,15],["H0784","a fire",16,22],["H4124","upon Moab",23,32],["H0398","and it shall devour",34,53],["H0759","the palaces",54,65],["H7152","of Kerioth",66,76],["H4124","and Moab",78,86],["H4191","shall die",87,96],["H7588","with tumult",97,108],["H8643","with shouting",110,123],["H6963","and with the sound",125,143],["H7782","of the trumpet",144,158]]},"2:3":{"text":"And I will cut off the judge from the midst thereof, and will slay all the princes thereof with him, saith the LORD.","words":[["H3772","And I will cut off",0,18],["H8199","the judge",19,28],["H7130","from the midst",29,43],["H2026","thereof, and will slay",44,66],["H8269","all the princes",67,82],["H0559","thereof with him, saith",83,106],["H3068","the LORD",107,115]]},"2:4":{"text":"Thus saith the LORD; For three transgressions of Judah, and for four, I will not turn away the punishment thereof; because they have despised the law of the LORD, and have not kept his commandments, and their lies caused them to err, after the which their fathers have walked:","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H7969","For three",21,30],["H6588","transgressions",31,45],["H3063","of Judah",46,54],["H0702","and for four",56,68],["H7725","I will not turn away",70,90],["H3988","the punishment thereof; because they have despised",91,141],["H8451","the law",142,149],["H3068","of the LORD",150,161],["H8104","and have not kept",163,180],["H2706","his commandments",181,197],["H3577","and their lies",199,213],["H8582","caused them to err",214,232],["H0310","after",234,239],["H0001","the which their fathers",240,263],["H1980","have walked",264,275]]},"2:5":{"text":"But I will send a fire upon Judah, and it shall devour the palaces of Jerusalem.","words":[["H7971","But I will send",0,15],["H0784","a fire",16,22],["H3063","upon Judah",23,33],["H0398","and it shall devour",35,54],["H0759","the palaces",55,66],["H3389","of Jerusalem",67,79]]},"2:6":{"text":"Thus saith the LORD; For three transgressions of Israel, and for four, I will not turn away the punishment thereof; because they sold the righteous for silver, and the poor for a pair of shoes;","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H7969","For three",21,30],["H6588","transgressions",31,45],["H3478","of Israel",46,55],["H0702","and for four",57,69],["H7725","I will not turn away",71,91],["H4376","the punishment thereof; because they sold",92,133],["H6662","the righteous",134,147],["H3701","for silver",148,158],["H0034","and the poor",160,172],["H5275","for a pair of shoes",173,192]]},"2:7":{"text":"That pant after the dust of the earth on the head of the poor, and turn aside the way of the meek: and a man and his father will go in unto the same maid, to profane my holy name:","words":[["H7602","That pant",0,9],["H6083","after the dust",10,24],["H0776","of the earth",25,37],["H7218","on the head",38,49],["H1800","of the poor",50,61],["H5186","and turn aside",63,77],["H1870","the way",78,85],["H6035","of the meek",86,97],["H0376","and a man",99,108],["H0001","and his father",109,123],["H3212","will go",124,131],["H5291","in unto the same maid",132,153],["H2490","to profane",155,165],["H6944","my holy",166,173],["H8034","name",174,178]]},"2:8":{"text":"And they lay themselves down upon clothes laid to pledge by every altar, and they drink the wine of the condemned in the house of their god.","words":[["H5186","And they lay themselves down",0,28],["H0899","upon clothes",29,41],["H2254","laid to pledge",42,56],["H0681","by",57,59],["H4196","every altar",60,71],["H8354","and they drink",73,87],["H3196","the wine",88,96],["H6064","of the condemned",97,113],["H1004","in the house",114,126],["H0430","of their god",127,139]]},"2:9":{"text":"Yet destroyed I the Amorite before them, whose height was like the height of the cedars, and he was strong as the oaks; yet I destroyed his fruit from above, and his roots from beneath.","words":[["H8045","Yet destroyed",0,13],["H0567","I the Amorite",14,27],["H6440","before",28,34],["H1363","them, whose height",35,53],["H1363","was like the height",54,73],["H0730","of the cedars",74,87],["H2634","and he was strong",89,106],["H0437","as the oaks",107,118],["H8045","yet I destroyed",120,135],["H6529","his fruit",136,145],["H4605","from above",146,156],["H8328","and his roots",158,171]]},"2:10":{"text":"Also I brought you up from the land of Egypt, and led you forty years through the wilderness, to possess the land of the Amorite.","words":[["H5927","Also I brought you up",0,21],["H0776","from the land",22,35],["H4714","of Egypt",36,44],["H3212","and led",46,53],["H0705","you forty",54,63],["H8141","years",64,69],["H4057","through the wilderness",70,92],["H3423","to possess",94,104],["H0776","the land",105,113],["H0567","of the Amorite",114,128]]},"2:11":{"text":"And I raised up of your sons for prophets, and of your young men for Nazarites. Is it not even thus, O ye children of Israel? saith the LORD.","words":[["H6965","And I raised up",0,15],["H1121","of your sons",16,28],["H5030","for prophets",29,41],["H0970","and of your young men",43,64],["H5139","for Nazarites",65,78],["H1121","Is it not even thus, O ye children",80,114],["H3478","of Israel",115,124],["H5002","saith",126,131],["H3068","the LORD",132,140]]},"2:12":{"text":"But ye gave the Nazarites wine to drink; and commanded the prophets, saying, Prophesy not.","words":[["H5139","But ye gave the Nazarites",0,25],["H3196","wine",26,30],["H8248","to drink",31,39],["H6680","and commanded",41,54],["H5030","the prophets",55,67],["H0559","saying",69,75],["H5012","Prophesy",77,85]]},"2:13":{"text":"Behold, I am pressed under you, as a cart is pressed that is full of sheaves.","words":[["H5781","Behold, I am pressed",0,20],["H5699","under you, as a cart",21,41],["H5781","is pressed",42,52],["H4392","that is full",53,65],["H5995","of sheaves",66,76]]},"2:14":{"text":"Therefore the flight shall perish from the swift, and the strong shall not strengthen his force, neither shall the mighty deliver himself:","words":[["H4498","Therefore the flight",0,20],["H0006","shall perish",21,33],["H7031","from the swift",34,48],["H2389","and the strong",50,64],["H0553","shall not strengthen",65,85],["H3581","his force",86,95],["H1368","neither shall the mighty",97,121],["H4422","deliver",122,129],["H5315","himself",130,137]]},"2:15":{"text":"Neither shall he stand that handleth the bow; and he that is swift of foot shall not deliver himself: neither shall he that rideth the horse deliver himself.","words":[["H5975","Neither shall he stand",0,22],["H8610","that handleth",23,36],["H7198","the bow",37,44],["H7031","and he that is swift",46,66],["H7272","of foot",67,74],["H4422","shall not deliver",75,92],["H7392","himself: neither shall he that rideth",93,130],["H5483","the horse",131,140],["H4422","deliver",141,148],["H5315","himself",149,156]]},"2:16":{"text":"And he that is courageous among the mighty shall flee away naked in that day, saith the LORD.","words":[["H0533","And he that is courageous",0,25],["H3820","And he that is courageous",0,25],["H1368","among the mighty",26,42],["H5127","shall flee away",43,58],["H6174","naked",59,64],["H3117","in that day",65,76],["H5002","saith",78,83],["H3068","the LORD",84,92]]},"3:1":{"text":"Hear this word that the LORD hath spoken against you, O children of Israel, against the whole family which I brought up from the land of Egypt, saying,","words":[["H8085","Hear",0,4],["H1697","this word",5,14],["H3068","that the LORD",15,28],["H1696","hath spoken",29,40],["H1121","against you, O children",41,64],["H3478","of Israel",65,74],["H4940","against the whole family",76,100],["H5927","which I brought up",101,119],["H0776","from the land",120,133],["H4714","of Egypt",134,142],["H0559","saying",144,150]]},"3:2":{"text":"You only have I known of all the families of the earth: therefore I will punish you for all your iniquities.","words":[["H3045","You only have I known",0,21],["H4940","of all the families",22,41],["H0127","of the earth",42,54],["H6485","therefore I will punish",56,79],["H5771","you for all your iniquities",80,107]]},"3:3":{"text":"Can two walk together, except they be agreed?","words":[["H8147","Can two",0,7],["H3212","walk",8,12],["H3162","together",13,21],["H1115","except",23,29],["H3259","they be agreed",30,44]]},"3:4":{"text":"Will a lion roar in the forest, when he hath no prey? will a young lion cry out of his den, if he have taken nothing?","words":[["H0738","Will a lion",0,11],["H7580","roar",12,16],["H3293","in the forest",17,30],["H2964","when he hath no prey",32,52],["H3715","will a young lion",54,71],["H5414","cry out",72,79],["H6963","cry out",72,79],["H4585","of his den",80,90],["H3920","if he have taken",92,108],["H1115","nothing",109,116]]},"3:5":{"text":"Can a bird fall in a snare upon the earth, where no gin is for him? shall one take up a snare from the earth, and have taken nothing at all?","words":[["H6833","Can a bird",0,10],["H5307","fall",11,15],["H6341","in a snare",16,26],["H0776","upon the earth",27,41],["H4170","where no gin",43,55],["H5927","is for him? shall one take up",56,85],["H6341","a snare",86,93],["H0127","from the earth",94,108],["H3920","and have taken",110,124],["H3920","nothing at all",125,139]]},"3:6":{"text":"Shall a trumpet be blown in the city, and the people not be afraid? shall there be evil in a city, and the LORD hath not done it?","words":[["H7782","Shall a trumpet",0,15],["H8628","be blown",16,24],["H5892","in the city",25,36],["H5971","and the people",38,52],["H2729","not be afraid",53,66],["H7451","shall there be evil",68,87],["H5892","in a city",88,97],["H3068","and the LORD",99,111],["H6213","hath not done",112,125]]},"3:7":{"text":"Surely the Lord GOD will do nothing, but he revealeth his secret unto his servants the prophets.","words":[["H0136","Surely the Lord",0,15],["H3069","GOD",16,19],["H6213","will do",20,27],["H1697","nothing",28,35],["H1540","but he revealeth",37,53],["H5475","his secret",54,64],["H5650","unto his servants",65,82],["H5030","the prophets",83,95]]},"3:8":{"text":"The lion hath roared, who will not fear? the Lord GOD hath spoken, who can but prophesy?","words":[["H0738","The lion",0,8],["H7580","hath roared",9,20],["H3808","who will not",22,34],["H3372","fear",35,39],["H0136","the Lord",41,49],["H3069","GOD",50,53],["H1696","hath spoken",54,65],["H5012","who can but prophesy",67,87]]},"3:9":{"text":"Publish in the palaces at Ashdod, and in the palaces in the land of Egypt, and say, Assemble yourselves upon the mountains of Samaria, and behold the great tumults in the midst thereof, and the oppressed in the midst thereof.","words":[["H8085","Publish",0,7],["H0759","in the palaces",8,22],["H0795","at Ashdod",23,32],["H0759","and in the palaces",34,52],["H0776","in the land",53,64],["H4714","of Egypt",65,73],["H0559","and say",75,82],["H0622","Assemble",84,92],["H2022","yourselves upon the mountains",93,122],["H8111","of Samaria",123,133],["H7200","and behold",135,145],["H7227","the great",146,155],["H4103","tumults",156,163],["H7130","in the midst",164,176],["H6217","thereof, and the oppressed",177,203],["H8432","in the midst",204,216]]},"3:10":{"text":"For they know not to do right, saith the LORD, who store up violence and robbery in their palaces.","words":[["H3045","For they know",0,13],["H6213","not to do",14,23],["H5229","right",24,29],["H5002","saith",31,36],["H3068","the LORD",37,45],["H0686","who store",47,56],["H2555","up violence",57,68],["H7701","and robbery",69,80],["H0759","in their palaces",81,97]]},"3:11":{"text":"Therefore thus saith the Lord GOD; An adversary there shall be even round about the land; and he shall bring down thy strength from thee, and thy palaces shall be spoiled.","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H6862","An adversary",35,47],["H5439","there shall be even round about",48,79],["H0776","the land",80,88],["H3381","and he shall bring down",90,113],["H5797","thy strength",114,126],["H0759","from thee, and thy palaces",127,153],["H0962","shall be spoiled",154,170]]},"3:12":{"text":"Thus saith the LORD; As the shepherd taketh out of the mouth of the lion two legs, or a piece of an ear; so shall the children of Israel be taken out that dwell in Samaria in the corner of a bed, and in Damascus in a couch.","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H7462","As the shepherd",21,36],["H5337","taketh out",37,47],["H6310","of the mouth",48,60],["H0738","of the lion",61,72],["H8147","two",73,76],["H3767","legs",77,81],["H0915","or a piece",83,93],["H0241","of an ear",94,103],["H1121","so shall the children",105,126],["H3478","of Israel",127,136],["H5337","be taken out",137,149],["H3427","that dwell",150,160],["H8111","in Samaria",161,171],["H6285","in the corner",172,185],["H4296","of a bed",186,194],["H1833","and in Damascus",196,211],["H6210","in a couch",212,222]]},"3:13":{"text":"Hear ye, and testify in the house of Jacob, saith the Lord GOD, the God of hosts,","words":[["H8085","Hear",0,4],["H5749","ye, and testify",5,20],["H1004","in the house",21,33],["H3290","of Jacob",34,42],["H5002","saith",44,49],["H0136","the Lord",50,58],["H3069","GOD",59,62],["H0430","the God",64,71],["H6635","of hosts",72,80]]},"3:14":{"text":"That in the day that I shall visit the transgressions of Israel upon him I will also visit the altars of Bethel: and the horns of the altar shall be cut off, and fall to the ground.","words":[["H3117","That in the day",0,15],["H6485","that I shall visit",16,34],["H6588","the transgressions",35,53],["H3478","of Israel",54,63],["H6485","upon him I will also visit",64,90],["H4196","the altars",91,101],["H1008","of Bethel",102,111],["H7161","and the horns",113,126],["H4196","of the altar",127,139],["H1438","shall be cut off",140,156],["H5307","and fall",158,166],["H0776","to the ground",167,180]]},"3:15":{"text":"And I will smite the winter house with the summer house; and the houses of ivory shall perish, and the great houses shall have an end, saith the LORD.","words":[["H5221","And I will smite",0,16],["H2779","the winter",17,27],["H1004","house",28,33],["H7019","with the summer",34,49],["H1004","house",50,55],["H1004","and the houses",57,71],["H8127","of ivory",72,80],["H0006","shall perish",81,93],["H7227","and the great",95,108],["H1004","houses",109,115],["H5486","shall have an end",116,133],["H5002","saith",135,140],["H3068","the LORD",141,149]]},"4:1":{"text":"Hear this word, ye kine of Bashan, that are in the mountain of Samaria, which oppress the poor, which crush the needy, which say to their masters, Bring, and let us drink.","words":[["H8085","Hear",0,4],["H1697","this word",5,14],["H6510","ye kine",16,23],["H1316","of Bashan",24,33],["H2022","that are in the mountain",35,59],["H8111","of Samaria",60,70],["H6231","which oppress",72,85],["H1800","the poor",86,94],["H7533","which crush",96,107],["H0034","the needy",108,117],["H0559","which say",119,128],["H0113","to their masters",129,145],["H0935","Bring",147,152],["H8354","and let us drink",154,170]]},"4:2":{"text":"The Lord GOD hath sworn by his holiness, that, lo, the days shall come upon you, that he will take you away with hooks, and your posterity with fishhooks.","words":[["H0136","The Lord",0,8],["H3069","GOD",9,12],["H7650","hath sworn",13,23],["H6944","by his holiness",24,39],["H3117","that, lo, the days",41,59],["H0935","shall come",60,70],["H5375","upon you, that he will take you away",71,107],["H6793","with hooks",108,118],["H0319","and your posterity",120,138],["H1729","with fishhooks",139,153],["H5518","with fishhooks",139,153]]},"4:3":{"text":"And ye shall go out at the breaches, every cow at that which is before her; and ye shall cast them into the palace, saith the LORD.","words":[["H3318","And ye shall go out",0,19],["H6556","at the breaches",20,35],["H0802","every",37,42],["H7993","cow at that which is before her; and ye shall cast",43,93],["H2038","them into the palace",94,114],["H5002","saith",116,121],["H3068","the LORD",122,130]]},"4:4":{"text":"Come to Bethel, and transgress; at Gilgal multiply transgression; and bring your sacrifices every morning, and your tithes after three years:","words":[["H0935","Come",0,4],["H1008","to Bethel",5,14],["H6586","and transgress",16,30],["H1537","at Gilgal",32,41],["H7235","multiply",42,50],["H6586","transgression",51,64],["H0935","and bring",66,75],["H2077","your sacrifices",76,91],["H1242","every morning",92,105],["H4643","and your tithes",107,122],["H7969","after three",123,134],["H3117","years",135,140]]},"4:5":{"text":"And offer a sacrifice of thanksgiving with leaven, and proclaim and publish the free offerings: for this liketh you, O ye children of Israel, saith the Lord GOD.","words":[["H6999","And offer",0,9],["H8426","a sacrifice of thanksgiving",10,37],["H2557","with leaven",38,49],["H7121","and proclaim",51,63],["H8085","and publish",64,75],["H5071","the free offerings",76,94],["H3651","for this",96,104],["H0157","liketh",105,111],["H1121","you, O ye children",112,130],["H3478","of Israel",131,140],["H5002","saith",142,147],["H0136","the Lord",148,156],["H3069","GOD",157,160]]},"4:6":{"text":"And I also have given you cleanness of teeth in all your cities, and want of bread in all your places: yet have ye not returned unto me, saith the LORD.","words":[["H5414","And I also have given",0,21],["H5356","you cleanness",22,35],["H8127","of teeth",36,44],["H5892","in all your cities",45,63],["H2640","and want",65,73],["H3899","of bread",74,82],["H4725","in all your places",83,101],["H7725","yet have ye not returned",103,127],["H5002","unto me, saith",128,142],["H3068","the LORD",143,151]]},"4:7":{"text":"And also I have withholden the rain from you, when there were yet three months to the harvest: and I caused it to rain upon one city, and caused it not to rain upon another city: one piece was rained upon, and the piece whereupon it rained not withered.","words":[["H4513","And also I have withholden",0,26],["H1653","the rain",27,35],["H7969","from you, when there were yet three",36,71],["H2320","months",72,78],["H7105","to the harvest",79,93],["H4305","and I caused it to rain",95,118],["H0259","upon one",119,127],["H5892","city",128,132],["H4305","and caused it not to rain",134,159],["H0259","upon another",160,172],["H5892","city",173,177],["H0259","one",179,182],["H2513","piece",183,188],["H4305","was rained",189,199],["H2513","upon, and the piece",200,219],["H4305","whereupon it rained",220,239],["H3001","not withered",240,252]]},"4:8":{"text":"So two or three cities wandered unto one city, to drink water; but they were not satisfied: yet have ye not returned unto me, saith the LORD.","words":[["H8147","So two",0,6],["H7969","or three",7,15],["H5892","cities",16,22],["H5128","wandered",23,31],["H0259","unto one",32,40],["H5892","city",41,45],["H8354","to drink",47,55],["H4325","water",56,61],["H7646","but they were not satisfied",63,90],["H7725","yet have ye not returned",92,116],["H5002","unto me, saith",117,131],["H3068","the LORD",132,140]]},"4:9":{"text":"I have smitten you with blasting and mildew: when your gardens and your vineyards and your fig trees and your olive trees increased, the palmerworm devoured them: yet have ye not returned unto me, saith the LORD.","words":[["H5221","I have smitten",0,14],["H7711","you with blasting",15,32],["H3420","and mildew",33,43],["H1593","when your gardens",45,62],["H3754","and your vineyards",63,81],["H8384","and your fig trees",82,100],["H2132","and your olive trees",101,121],["H7235","increased",122,131],["H1501","the palmerworm",133,147],["H0398","devoured",148,156],["H7725","them: yet have ye not returned",157,187],["H5002","unto me, saith",188,202],["H3068","the LORD",203,211]]},"4:10":{"text":"I have sent among you the pestilence after the manner of Egypt: your young men have I slain with the sword, and have taken away your horses; and I have made the stink of your camps to come up unto your nostrils: yet have ye not returned unto me, saith the LORD.","words":[["H7971","I have sent",0,11],["H1698","among you the pestilence",12,36],["H1870","after the manner",37,53],["H4714","of Egypt",54,62],["H0970","your young men",64,78],["H2026","have I slain",79,91],["H2719","with the sword",92,106],["H7628","and have taken away",108,127],["H5483","your horses",128,139],["H0889","and I have made the stink",141,166],["H4264","of your camps",167,180],["H5927","to come up",181,191],["H0639","unto your nostrils",192,210],["H7725","yet have ye not returned",212,236],["H5002","unto me, saith",237,251],["H3068","the LORD",252,260]]},"4:11":{"text":"I have overthrown some of you, as God overthrew Sodom and Gomorrah, and ye were as a firebrand plucked out of the burning: yet have ye not returned unto me, saith the LORD.","words":[["H2015","I have overthrown",0,17],["H0430","some of you, as God",18,37],["H4114","overthrew",38,47],["H5467","Sodom",48,53],["H6017","and Gomorrah",54,66],["H0181","and ye were as a firebrand",68,94],["H5337","plucked out",95,106],["H8316","of the burning",107,121],["H7725","yet have ye not returned",123,147],["H5002","unto me, saith",148,162],["H3068","the LORD",163,171]]},"4:12":{"text":"Therefore thus will I do unto thee, O Israel: and because I will do this unto thee, prepare to meet thy God, O Israel.","words":[["H6213","Therefore thus will I do",0,24],["H3478","unto thee, O Israel",25,44],["H6118","and because",46,57],["H6213","I will do",58,67],["H3559","this unto thee, prepare",68,91],["H7125","to meet",92,99],["H0430","thy God",100,107],["H3478","O Israel",109,117]]},"4:13":{"text":"For, lo, he that formeth the mountains, and createth the wind, and declareth unto man what is his thought, that maketh the morning darkness, and treadeth upon the high places of the earth, The LORD, The God of hosts, is his name.","words":[["H3335","For, lo, he that formeth",0,24],["H2022","the mountains",25,38],["H1254","and createth",40,52],["H7307","the wind",53,61],["H5046","and declareth",63,76],["H0120","unto man",77,85],["H7808","what is his thought",86,105],["H6213","that maketh",107,118],["H7837","the morning",119,130],["H5890","darkness",131,139],["H1869","and treadeth",141,153],["H1116","upon the high places",154,174],["H0776","of the earth",175,187],["H3068","The LORD",189,197],["H0430","The God",199,206],["H6635","of hosts",207,215],["H8034","is his name",217,228]]},"5:1":{"text":"Hear ye this word which I take up against you, even a lamentation, O house of Israel.","words":[["H8085","Hear",0,4],["H1697","ye this word",5,17],["H5375","which I take up",18,33],["H7015","against you, even a lamentation",34,65],["H1004","O house",67,74],["H3478","of Israel",75,84]]},"5:2":{"text":"The virgin of Israel is fallen; she shall no more rise: she is forsaken upon her land; there is none to raise her up.","words":[["H1330","The virgin",0,10],["H3478","of Israel",11,20],["H5307","is fallen",21,30],["H3254","she shall no more",32,49],["H6965","rise",50,54],["H5203","she is forsaken",56,71],["H0127","upon her land",72,85],["H6965","there is none to raise her up",87,116]]},"5:3":{"text":"For thus saith the Lord GOD; The city that went out by a thousand shall leave an hundred, and that which went forth by an hundred shall leave ten, to the house of Israel.","words":[["H0559","For thus saith",0,14],["H0136","the Lord",15,23],["H3069","GOD",24,27],["H5892","The city",29,37],["H3318","that went out",38,51],["H0505","by a thousand",52,65],["H7604","shall leave",66,77],["H3967","an hundred",78,88],["H3318","and that which went forth",90,115],["H3967","by an hundred",116,129],["H7604","shall leave",130,141],["H6235","ten",142,145],["H1004","to the house",147,159],["H3478","of Israel",160,169]]},"5:4":{"text":"For thus saith the LORD unto the house of Israel, Seek ye me, and ye shall live:","words":[["H0559","For thus saith",0,14],["H3068","the LORD",15,23],["H1004","unto the house",24,38],["H3478","of Israel",39,48],["H1875","Seek",50,54],["H2421","ye me, and ye shall live",55,79]]},"5:5":{"text":"But seek not Bethel, nor enter into Gilgal, and pass not to Beersheba: for Gilgal shall surely go into captivity, and Bethel shall come to nought.","words":[["H1875","But seek",0,8],["H1008","not Bethel",9,19],["H0935","nor enter",21,30],["H1537","into Gilgal",31,42],["H5674","and pass",44,52],["H0884","not to Beersheba",53,69],["H1537","for Gilgal",71,81],["H1540","shall surely",82,94],["H1540","go into captivity",95,112],["H1008","and Bethel",114,124],["H0205","shall come to nought",125,145]]},"5:6":{"text":"Seek the LORD, and ye shall live; lest he break out like fire in the house of Joseph, and devour it, and there be none to quench it in Bethel.","words":[["H1875","Seek",0,4],["H3068","the LORD",5,13],["H2421","and ye shall live",15,32],["H6743","lest he break out",34,51],["H0784","like fire",52,61],["H1004","in the house",62,74],["H3130","of Joseph",75,84],["H0398","and devour",86,96],["H3518","it, and there be none to quench",97,128],["H1008","it in Bethel",129,141]]},"5:7":{"text":"Ye who turn judgment to wormwood, and leave off righteousness in the earth,","words":[["H2015","Ye who turn",0,11],["H4941","judgment",12,20],["H3939","to wormwood",21,32],["H3240","and leave off",34,47],["H6666","righteousness",48,61],["H0776","in the earth",62,74]]},"5:8":{"text":"Seek him that maketh the seven stars and Orion, and turneth the shadow of death into the morning, and maketh the day dark with night: that calleth for the waters of the sea, and poureth them out upon the face of the earth: The LORD is his name:","words":[["H6213","Seek him that maketh",0,20],["H3598","the seven stars",21,36],["H3685","and Orion",37,46],["H2015","and turneth",48,59],["H6757","the shadow of death",60,79],["H1242","into the morning",80,96],["H3117","and maketh the day",98,116],["H2821","dark",117,121],["H3915","with night",122,132],["H7121","that calleth",134,146],["H4325","for the waters",147,161],["H3220","of the sea",162,172],["H8210","and poureth them out",174,194],["H6440","upon the face",195,208],["H0776","of the earth",209,221],["H3068","The LORD",223,231],["H8034","is his name",232,243]]},"5:9":{"text":"That strengtheneth the spoiled against the strong, so that the spoiled shall come against the fortress.","words":[["H1082","That strengtheneth",0,18],["H7701","the spoiled",19,30],["H5794","against the strong",31,49],["H7701","so that the spoiled",51,70],["H0935","shall come",71,81],["H4013","against the fortress",82,102]]},"5:10":{"text":"They hate him that rebuketh in the gate, and they abhor him that speaketh uprightly.","words":[["H8130","They hate",0,9],["H3198","him that rebuketh",10,27],["H8179","in the gate",28,39],["H8581","and they abhor",41,55],["H1696","him that speaketh",56,73],["H8549","uprightly",74,83]]},"5:11":{"text":"Forasmuch therefore as your treading is upon the poor, and ye take from him burdens of wheat: ye have built houses of hewn stone, but ye shall not dwell in them; ye have planted pleasant vineyards, but ye shall not drink wine of them.","words":[["H3282","Forasmuch",0,9],["H1318","therefore as your treading",10,36],["H1800","is upon the poor",37,53],["H3947","and ye take",55,66],["H4864","from him burdens",67,83],["H1250","of wheat",84,92],["H1129","ye have built",94,107],["H1004","houses",108,114],["H1496","of hewn stone",115,128],["H3427","but ye shall not dwell",130,152],["H5193","in them; ye have planted",153,177],["H2531","pleasant",178,186],["H3754","vineyards",187,196],["H8354","but ye shall not drink",198,220],["H3196","wine",221,225]]},"5:12":{"text":"For I know your manifold transgressions and your mighty sins: they afflict the just, they take a bribe, and they turn aside the poor in the gate from their right.","words":[["H3045","For I know",0,10],["H7227","your manifold",11,24],["H6588","transgressions",25,39],["H6099","and your mighty",40,55],["H2403","sins",56,60],["H6887","they afflict",62,74],["H6662","the just",75,83],["H3947","they take",85,94],["H3724","a bribe",95,102],["H5186","and they turn aside",104,123],["H0034","the poor",124,132],["H8179","in the gate",133,144]]},"5:13":{"text":"Therefore the prudent shall keep silence in that time; for it is an evil time.","words":[["H7919","Therefore the prudent",0,21],["H1826","shall keep silence",22,40],["H6256","in that time",41,53],["H7451","for it is an evil",55,72],["H6256","time",73,77]]},"5:14":{"text":"Seek good, and not evil, that ye may live: and so the LORD, the God of hosts, shall be with you, as ye have spoken.","words":[["H1875","Seek",0,4],["H2896","good",5,9],["H7451","and not evil",11,23],["H2421","that ye may live",25,41],["H3068","and so the LORD",43,58],["H0430","the God",60,67],["H6635","of hosts",68,76],["H0559","shall be with you, as ye have spoken",78,114]]},"5:15":{"text":"Hate the evil, and love the good, and establish judgment in the gate: it may be that the LORD God of hosts will be gracious unto the remnant of Joseph.","words":[["H8130","Hate",0,4],["H7451","the evil",5,13],["H0157","and love",15,23],["H2896","the good",24,32],["H3322","and establish",34,47],["H4941","judgment",48,56],["H8179","in the gate",57,68],["H3068","it may be that the LORD",70,93],["H0430","God",94,97],["H6635","of hosts",98,106],["H2603","will be gracious",107,123],["H7611","unto the remnant",124,140],["H3130","of Joseph",141,150]]},"5:16":{"text":"Therefore the LORD, the God of hosts, the Lord, saith thus; Wailing shall be in all streets; and they shall say in all the highways, Alas! alas! and they shall call the husbandman to mourning, and such as are skilful of lamentation to wailing.","words":[["H3068","Therefore the LORD",0,18],["H0430","the God",20,27],["H6635","of hosts",28,36],["H0136","the Lord",38,46],["H0559","saith",48,53],["H4553","thus; Wailing",54,67],["H7339","shall be in all streets",68,91],["H0559","and they shall say",93,111],["H2351","in all the highways",112,131],["H1930","Alas",133,137],["H1930","alas",139,143],["H7121","and they shall call",145,164],["H0406","the husbandman",165,179],["H0060","to mourning",180,191],["H3045","and such as are skilful",193,216],["H5092","of lamentation",217,231],["H4553","to wailing",232,242]]},"5:17":{"text":"And in all vineyards shall be wailing: for I will pass through thee, saith the LORD.","words":[["H3754","And in all vineyards",0,20],["H4553","shall be wailing",21,37],["H5674","for I will pass",39,54],["H7130","through",55,62],["H0559","thee, saith",63,74],["H3068","the LORD",75,83]]},"5:18":{"text":"Woe unto you that desire the day of the LORD! to what end is it for you? the day of the LORD is darkness, and not light.","words":[["H1945","Woe",0,3],["H0183","unto you that desire",4,24],["H3117","the day",25,32],["H3068","of the LORD",33,44],["H4100","to what end",46,57],["H3117","is it for you? the day",58,80],["H3068","of the LORD",81,92],["H2822","is darkness",93,104],["H0216","and not light",106,119]]},"5:19":{"text":"As if a man did flee from a lion, and a bear met him; or went into the house, and leaned his hand on the wall, and a serpent bit him.","words":[["H0376","As if a man",0,11],["H5127","did flee",12,20],["H6440","from",21,25],["H0738","a lion",26,32],["H1677","and a bear",34,44],["H6293","met",45,48],["H0935","him; or went",49,61],["H1004","into the house",62,76],["H5564","and leaned",78,88],["H3027","his hand",89,97],["H7023","on the wall",98,109],["H5175","and a serpent",111,124],["H5391","bit",125,128]]},"5:20":{"text":"Shall not the day of the LORD be darkness, and not light? even very dark, and no brightness in it?","words":[["H3117","Shall not the day",0,17],["H3068","of the LORD",18,29],["H2822","be darkness",30,41],["H0216","and not light",43,56],["H0651","even very dark",58,72],["H5051","and no brightness",74,91]]},"5:21":{"text":"I hate, I despise your feast days, and I will not smell in your solemn assemblies.","words":[["H8130","I hate",0,6],["H3988","I despise",8,17],["H2282","your feast days",18,33],["H7306","and I will not smell",35,55],["H6116","in your solemn assemblies",56,81]]},"5:22":{"text":"Though ye offer me burnt offerings and your meat offerings, I will not accept them: neither will I regard the peace offerings of your fat beasts.","words":[["H5927","Though ye offer",0,15],["H5930","me burnt offerings",16,34],["H4503","and your meat offerings",35,58],["H7521","I will not accept",60,77],["H5027","them: neither will I regard",78,105],["H8002","the peace offerings",106,125],["H4806","of your fat beasts",126,144]]},"5:23":{"text":"Take thou away from me the noise of thy songs; for I will not hear the melody of thy viols.","words":[["H5493","Take thou away",0,14],["H1995","from me the noise",15,32],["H7892","of thy songs",33,45],["H8085","for I will not hear",47,66],["H2172","the melody",67,77],["H5035","of thy viols",78,90]]},"5:24":{"text":"But let judgment run down as waters, and righteousness as a mighty stream.","words":[["H4941","But let judgment",0,16],["H1556","run down",17,25],["H4325","as waters",26,35],["H6666","and righteousness",37,54],["H0386","as a mighty",55,66],["H5158","stream",67,73]]},"5:25":{"text":"Have ye offered unto me sacrifices and offerings in the wilderness forty years, O house of Israel?","words":[["H5066","Have ye offered",0,15],["H2077","unto me sacrifices",16,34],["H4503","and offerings",35,48],["H4057","in the wilderness",49,66],["H0705","forty",67,72],["H8141","years",73,78],["H1004","O house",80,87],["H3478","of Israel",88,97]]},"5:26":{"text":"But ye have borne the tabernacle of your Moloch and Chiun your images, the star of your god, which ye made to yourselves.","words":[["H5375","But ye have borne",0,17],["H5522","the tabernacle",18,32],["H4428","of your Moloch",33,47],["H3594","and Chiun",48,57],["H6754","your images",58,69],["H3556","the star",71,79],["H0430","of your god",80,91],["H6213","which ye made",93,106]]},"5:27":{"text":"Therefore will I cause you to go into captivity beyond Damascus, saith the LORD, whose name is The God of hosts.","words":[["H1540","Therefore will I cause you to go into captivity",0,47],["H1973","beyond",48,54],["H1834","Damascus",55,63],["H0559","saith",65,70],["H3068","the LORD",71,79],["H8034","whose name",81,91],["H0430","is The God",92,102],["H6635","of hosts",103,111]]},"6:1":{"text":"Woe to them that are at ease in Zion, and trust in the mountain of Samaria, which are named chief of the nations, to whom the house of Israel came!","words":[["H1945","Woe",0,3],["H7600","to them that are at ease",4,28],["H6726","in Zion",29,36],["H0982","and trust",38,47],["H2022","in the mountain",48,63],["H8111","of Samaria",64,74],["H5344","which are named",76,91],["H7225","chief",92,97],["H1471","of the nations",98,112],["H1004","to whom the house",114,131],["H3478","of Israel",132,141],["H0935","came",142,146]]},"6:2":{"text":"Pass ye unto Calneh, and see; and from thence go ye to Hamath the great: then go down to Gath of the Philistines: be they better than these kingdoms? or their border greater than your border?","words":[["H5674","Pass",0,4],["H3641","ye unto Calneh",5,19],["H7200","and see",21,28],["H3212","and from thence go",30,48],["H2574","ye to Hamath",49,61],["H7227","the great",62,71],["H2579","the great",62,71],["H3381","then go down",73,85],["H1661","to Gath",86,93],["H6430","of the Philistines",94,112],["H2896","be they better",114,128],["H4467","than these kingdoms",129,148],["H1366","or their border",150,165],["H7227","greater",166,173],["H1366","than your border",174,190]]},"6:3":{"text":"Ye that put far away the evil day, and cause the seat of violence to come near;","words":[["H5077","Ye that put far away",0,20],["H7451","the evil",21,29],["H3117","day",30,33],["H7675","and cause the seat",35,53],["H2555","of violence",54,65],["H5066","to come near",66,78]]},"6:4":{"text":"That lie upon beds of ivory, and stretch themselves upon their couches, and eat the lambs out of the flock, and the calves out of the midst of the stall;","words":[["H7901","That lie",0,8],["H4296","upon beds",9,18],["H8127","of ivory",19,27],["H5628","and stretch",29,40],["H6210","themselves upon their couches",41,70],["H0398","and eat",72,79],["H3733","the lambs",80,89],["H6629","out of the flock",90,106],["H5695","and the calves",108,122],["H8432","out of the midst",123,139],["H4770","of the stall",140,152]]},"6:5":{"text":"That chant to the sound of the viol, and invent to themselves instruments of musick, like David;","words":[["H6527","That chant",0,10],["H6310","to the sound",11,23],["H5035","of the viol",24,35],["H2803","and invent",37,47],["H3627","to themselves instruments",48,73],["H7892","of musick",74,83],["H1732","like David",85,95]]},"6:6":{"text":"That drink wine in bowls, and anoint themselves with the chief ointments: but they are not grieved for the affliction of Joseph.","words":[["H8354","That drink",0,10],["H3196","wine",11,15],["H4219","in bowls",16,24],["H4886","and anoint",26,36],["H7225","themselves with the chief",37,62],["H8081","ointments",63,72],["H2470","but they are not grieved",74,98],["H7667","for the affliction",99,117],["H3130","of Joseph",118,127]]},"6:7":{"text":"Therefore now shall they go captive with the first that go captive, and the banquet of them that stretched themselves shall be removed.","words":[["H1540","Therefore now shall they go captive",0,35],["H7218","with the first",36,50],["H1540","that go captive",51,66],["H4797","and the banquet",68,83],["H5628","of them that stretched",84,106],["H5493","themselves shall be removed",107,134]]},"6:8":{"text":"The Lord GOD hath sworn by himself, saith the LORD the God of hosts, I abhor the excellency of Jacob, and hate his palaces: therefore will I deliver up the city with all that is therein.","words":[["H0136","The Lord",0,8],["H3069","GOD",9,12],["H7650","hath sworn",13,23],["H5315","by himself",24,34],["H5002","saith",36,41],["H3068","the LORD",42,50],["H0430","the God",51,58],["H6635","of hosts",59,67],["H8374","I abhor",69,76],["H1347","the excellency",77,91],["H3290","of Jacob",92,100],["H8130","and hate",102,110],["H0759","his palaces",111,122],["H5462","therefore will I deliver up",124,151],["H5892","the city",152,160],["H4393","with all that is therein",161,185]]},"6:9":{"text":"And it shall come to pass, if there remain ten men in one house, that they shall die.","words":[["H3498","And it shall come to pass, if there remain",0,42],["H6235","ten",43,46],["H0582","men",47,50],["H0259","in one",51,57],["H1004","house",58,63],["H4191","that they shall die",65,84]]},"6:10":{"text":"And a man's uncle shall take him up, and he that burneth him, to bring out the bones out of the house, and shall say unto him that is by the sides of the house, Is there yet any with thee? and he shall say, No. Then shall he say, Hold thy tongue: for we may not make mention of the name of the LORD.","words":[["H1730","And a man's uncle",0,17],["H5375","shall take him up",18,35],["H5635","and he that burneth",37,56],["H3318","him, to bring out",57,74],["H6106","the bones",75,84],["H1004","out of the house",85,101],["H0559","and shall say",103,116],["H3411","unto him that is by the sides",117,146],["H1004","of the house",147,159],["H0559","Is there yet any with thee? and he shall say",161,205],["H0657","No",207,209],["H0559","Then shall he say",211,228],["H2013","Hold thy tongue",230,245],["H2142","for we may not make mention",247,274],["H8034","of the name",275,286],["H3068","of the LORD",287,298]]},"6:11":{"text":"For, behold, the LORD commandeth, and he will smite the great house with breaches, and the little house with clefts.","words":[["H3068","For, behold, the LORD",0,21],["H6680","commandeth",22,32],["H5221","and he will smite",34,51],["H1419","the great",52,61],["H1004","house",62,67],["H7447","with breaches",68,81],["H6996","and the little",83,97],["H1004","house",98,103],["H1233","with clefts",104,115]]},"6:12":{"text":"Shall horses run upon the rock? will one plow there with oxen? for ye have turned judgment into gall, and the fruit of righteousness into hemlock:","words":[["H5483","Shall horses",0,12],["H7323","run",13,16],["H5553","upon the rock",17,30],["H2790","will one plow",32,45],["H1241","there with oxen",46,61],["H2015","for ye have turned",63,81],["H4941","judgment",82,90],["H7219","into gall",91,100],["H6529","and the fruit",102,115],["H6666","of righteousness",116,132],["H3939","into hemlock",133,145]]},"6:13":{"text":"Ye which rejoice in a thing of nought, which say, Have we not taken to us horns by our own strength?","words":[["H8056","Ye which rejoice",0,16],["H1697","in a thing",17,27],["H3808","of nought",28,37],["H0559","which say",39,48],["H3947","Have we not taken",50,67],["H7161","to us horns",68,79],["H2392","by our own strength",80,99]]},"6:14":{"text":"But, behold, I will raise up against you a nation, O house of Israel, saith the LORD the God of hosts; and they shall afflict you from the entering in of Hemath unto the river of the wilderness.","words":[["H6965","But, behold, I will raise up",0,28],["H1471","against you a nation",29,49],["H1004","O house",51,58],["H3478","of Israel",59,68],["H5002","saith",70,75],["H3068","the LORD",76,84],["H0430","the God",85,92],["H6635","of hosts",93,101],["H3905","and they shall afflict",103,125],["H0935","you from the entering in",126,150],["H2574","of Hemath",151,160],["H5158","unto the river",161,175],["H6160","of the wilderness",176,193]]},"7:1":{"text":"Thus hath the Lord GOD shewed unto me; and, behold, he formed grasshoppers in the beginning of the shooting up of the latter growth; and, lo, it was the latter growth after the king's mowings.","words":[["H0136","Thus hath the Lord",0,18],["H3069","GOD",19,22],["H7200","shewed",23,29],["H3335","unto me; and, behold, he formed",30,61],["H1462","grasshoppers",62,74],["H8462","in the beginning",75,91],["H5927","of the shooting up",92,110],["H3954","of the latter growth",111,131],["H3954","and, lo, it was the latter growth",133,166],["H0310","after",167,172],["H4428","the king's",173,183],["H1488","mowings",184,191]]},"7:2":{"text":"And it came to pass, that when they had made an end of eating the grass of the land, then I said, O Lord GOD, forgive, I beseech thee: by whom shall Jacob arise? for he is small.","words":[["H3615","And it came to pass, that when they had made an end",0,51],["H0398","of eating",52,61],["H6212","the grass",62,71],["H0776","of the land",72,83],["H0559","then I said",85,96],["H0136","O Lord",98,104],["H3069","GOD",105,108],["H5545","forgive",110,117],["H3290","I beseech thee: by whom shall Jacob",119,154],["H6965","arise",155,160],["H6996","for he is small",162,177]]},"7:3":{"text":"The LORD repented for this: It shall not be, saith the LORD.","words":[["H3068","The LORD",0,8],["H5162","repented",9,17],["H0559","for this: It shall not be, saith",18,50],["H3068","the LORD",51,59]]},"7:4":{"text":"Thus hath the Lord GOD shewed unto me: and, behold, the Lord GOD called to contend by fire, and it devoured the great deep, and did eat up a part.","words":[["H0136","Thus hath the Lord",0,18],["H3069","GOD",19,22],["H7200","shewed",23,29],["H0136","unto me: and, behold, the Lord",30,60],["H3069","GOD",61,64],["H7121","called",65,71],["H7378","to contend",72,82],["H0784","by fire",83,90],["H0398","and it devoured",92,107],["H7227","the great",108,117],["H8415","deep",118,122],["H0398","and did eat up",124,138],["H2506","a part",139,145]]},"7:5":{"text":"Then said I, O Lord GOD, cease, I beseech thee: by whom shall Jacob arise? for he is small.","words":[["H0559","Then said",0,9],["H0136","I, O Lord",10,19],["H3069","GOD",20,23],["H2308","cease",25,30],["H3290","I beseech thee: by whom shall Jacob",32,67],["H6965","arise",68,73],["H6996","for he is small",75,90]]},"7:6":{"text":"The LORD repented for this: This also shall not be, saith the Lord GOD.","words":[["H3068","The LORD",0,8],["H5162","repented",9,17],["H0559","for this: This also shall not be, saith",18,57],["H0136","the Lord",58,66],["H3069","GOD",67,70]]},"7:7":{"text":"Thus he shewed me: and, behold, the Lord stood upon a wall made by a plumbline, with a plumbline in his hand.","words":[["H7200","Thus he shewed",0,14],["H0136","me: and, behold, the Lord",15,40],["H5324","stood",41,46],["H2346","upon a wall",47,58],["H0594","made by a plumbline",59,78],["H0594","with a plumbline",80,96],["H3027","in his hand",97,108]]},"7:8":{"text":"And the LORD said unto me, Amos, what seest thou? And I said, A plumbline. Then said the Lord, Behold, I will set a plumbline in the midst of my people Israel: I will not again pass by them any more:","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H5986","unto me, Amos",18,31],["H7200","what seest",33,43],["H0559","thou? And I said",44,60],["H0594","A plumbline",62,73],["H0559","Then said",75,84],["H0136","the Lord",85,93],["H7760","Behold, I will set",95,113],["H0594","a plumbline",114,125],["H7130","in the midst",126,138],["H5971","of my people",139,151],["H3478","Israel",152,158],["H3254","I will not again",160,176],["H5674","pass by",177,184]]},"7:9":{"text":"And the high places of Isaac shall be desolate, and the sanctuaries of Israel shall be laid waste; and I will rise against the house of Jeroboam with the sword.","words":[["H1116","And the high places",0,19],["H3446","of Isaac",20,28],["H8074","shall be desolate",29,46],["H4720","and the sanctuaries",48,67],["H3478","of Israel",68,77],["H2717","shall be laid waste",78,97],["H6965","and I will rise",99,114],["H1004","against the house",115,132],["H3379","of Jeroboam",133,144],["H2719","with the sword",145,159]]},"7:10":{"text":"Then Amaziah the priest of Bethel sent to Jeroboam king of Israel, saying, Amos hath conspired against thee in the midst of the house of Israel: the land is not able to bear all his words.","words":[["H0558","Then Amaziah",0,12],["H3548","the priest",13,23],["H1008","of Bethel",24,33],["H7971","sent",34,38],["H3379","to Jeroboam",39,50],["H4428","king",51,55],["H3478","of Israel",56,65],["H0559","saying",67,73],["H5986","Amos",75,79],["H7194","hath conspired",80,94],["H7130","against thee in the midst",95,120],["H1004","of the house",121,133],["H3478","of Israel",134,143],["H0776","the land",145,153],["H3201","is not able",154,165],["H3557","to bear",166,173],["H1697","all his words",174,187]]},"7:11":{"text":"For thus Amos saith, Jeroboam shall die by the sword, and Israel shall surely be led away captive out of their own land.","words":[["H5986","For thus Amos",0,13],["H0559","saith",14,19],["H3379","Jeroboam",21,29],["H4191","shall die",30,39],["H2719","by the sword",40,52],["H3478","and Israel",54,64],["H1540","shall surely",65,77],["H1540","be led away captive",78,97],["H0127","out of their own land",98,119]]},"7:12":{"text":"Also Amaziah said unto Amos, O thou seer, go, flee thee away into the land of Judah, and there eat bread, and prophesy there:","words":[["H0558","Also Amaziah",0,12],["H0559","said",13,17],["H5986","unto Amos",18,27],["H2374","O thou seer",29,40],["H3212","go",42,44],["H1272","flee thee away",46,60],["H0776","into the land",61,74],["H3063","of Judah",75,83],["H0398","and there eat",85,98],["H3899","bread",99,104],["H5012","and prophesy",106,118]]},"7:13":{"text":"But prophesy not again any more at Bethel: for it is the king's chapel, and it is the king's court.","words":[["H5012","But prophesy",0,12],["H3254","not again",13,22],["H1008","any more at Bethel",23,41],["H4428","for it is the king's",43,63],["H4720","chapel",64,70],["H4467","and it is the king's",72,92],["H1004","court",93,98]]},"7:14":{"text":"Then answered Amos, and said to Amaziah, I was no prophet, neither was I a prophet's son; but I was an herdman, and a gatherer of sycomore fruit:","words":[["H6030","Then answered",0,13],["H5986","Amos",14,18],["H0559","and said",20,28],["H0558","to Amaziah",29,39],["H5030","I was no prophet",41,57],["H5030","neither was I a prophet's",59,84],["H1121","son",85,88],["H0951","but I was an herdman",90,110],["H1103","and a gatherer",112,126],["H8256","of sycomore fruit",127,144]]},"7:15":{"text":"And the LORD took me as I followed the flock, and the LORD said unto me, Go, prophesy unto my people Israel.","words":[["H3068","And the LORD",0,12],["H3947","took",13,17],["H0310","me as I followed",18,34],["H6629","the flock",35,44],["H3068","and the LORD",46,58],["H0559","said",59,63],["H3212","unto me, Go",64,75],["H5012","prophesy",77,85],["H5971","unto my people",86,100],["H3478","Israel",101,107]]},"7:16":{"text":"Now therefore hear thou the word of the LORD: Thou sayest, Prophesy not against Israel, and drop not thy word against the house of Isaac.","words":[["H8085","Now therefore hear",0,18],["H1697","thou the word",19,32],["H3068","of the LORD",33,44],["H0559","Thou sayest",46,57],["H5012","Prophesy",59,67],["H3478","not against Israel",68,86],["H5197","and drop",88,96],["H1004","not thy word against the house",97,127],["H3446","of Isaac",128,136]]},"7:17":{"text":"Therefore thus saith the LORD; Thy wife shall be an harlot in the city, and thy sons and thy daughters shall fall by the sword, and thy land shall be divided by line; and thou shalt die in a polluted land: and Israel shall surely go into captivity forth of his land.","words":[["H0559","Therefore thus saith",0,20],["H3068","the LORD",21,29],["H0802","Thy wife",31,39],["H2181","shall be an harlot",40,58],["H5892","in the city",59,70],["H1121","and thy sons",72,84],["H1323","and thy daughters",85,102],["H5307","shall fall",103,113],["H2719","by the sword",114,126],["H0127","and thy land",128,140],["H2505","shall be divided",141,157],["H2256","by line",158,165],["H4191","and thou shalt die",167,185],["H5921","in",186,188],["H2931","a polluted",189,199],["H0127","land",200,204],["H3478","and Israel",206,216],["H1540","shall surely",217,229],["H1540","go into captivity",230,247],["H0127","forth of his land",248,265]]},"8:1":{"text":"Thus hath the Lord GOD shewed unto me: and behold a basket of summer fruit.","words":[["H0136","Thus hath the Lord",0,18],["H3069","GOD",19,22],["H7200","shewed",23,29],["H3619","unto me: and behold a basket",30,58],["H7019","of summer fruit",59,74]]},"8:2":{"text":"And he said, Amos, what seest thou? And I said, A basket of summer fruit. Then said the LORD unto me, The end is come upon my people of Israel; I will not again pass by them any more.","words":[["H0559","And he said",0,11],["H5986","Amos",13,17],["H7200","what seest",19,29],["H0559","thou? And I said",30,46],["H3619","A basket",48,56],["H7019","of summer fruit",57,72],["H0559","Then said",74,83],["H3068","the LORD",84,92],["H7093","unto me, The end",93,109],["H0935","is come",110,117],["H5971","upon my people",118,132],["H3478","of Israel",133,142],["H3254","I will not again",144,160],["H5674","pass",161,165]]},"8:3":{"text":"And the songs of the temple shall be howlings in that day, saith the Lord GOD: there shall be many dead bodies in every place; they shall cast them forth with silence.","words":[["H7892","And the songs",0,13],["H1964","of the temple",14,27],["H3213","shall be howlings",28,45],["H3117","in that day",46,57],["H5002","saith",59,64],["H0136","the Lord",65,73],["H3069","GOD",74,77],["H7227","there shall be many",79,98],["H6297","dead bodies",99,110],["H4725","in every place",111,125],["H7993","they shall cast them forth",127,153],["H2013","with silence",154,166]]},"8:4":{"text":"Hear this, O ye that swallow up the needy, even to make the poor of the land to fail,","words":[["H8085","Hear",0,4],["H7602","this, O ye that swallow up",5,31],["H0034","the needy",32,41],["H7673","even to make",43,55],["H6041","the poor",56,64],["H6035","the poor",56,64],["H0776","of the land",65,76],["H7673","to fail",77,84]]},"8:5":{"text":"Saying, When will the new moon be gone, that we may sell corn? and the sabbath, that we may set forth wheat, making the ephah small, and the shekel great, and falsifying the balances by deceit?","words":[["H0559","Saying",0,6],["H2320","When will the new moon",8,30],["H5674","be gone",31,38],["H7666","that we may sell",40,56],["H7668","corn",57,61],["H7676","and the sabbath",63,78],["H6605","that we may set forth",80,101],["H1250","wheat",102,107],["H0374","making the ephah",109,125],["H6994","small",126,131],["H8255","and the shekel",133,147],["H1431","great",148,153],["H5791","and falsifying",155,169],["H3976","the balances",170,182],["H4820","by deceit",183,192]]},"8:6":{"text":"That we may buy the poor for silver, and the needy for a pair of shoes; yea, and sell the refuse of the wheat?","words":[["H7069","That we may buy",0,15],["H1800","the poor",16,24],["H3701","for silver",25,35],["H0034","and the needy",37,50],["H5275","for a pair of shoes",51,70],["H7666","yea, and sell",72,85],["H4651","the refuse",86,96],["H1250","of the wheat",97,109]]},"8:7":{"text":"The LORD hath sworn by the excellency of Jacob, Surely I will never forget any of their works.","words":[["H3068","The LORD",0,8],["H7650","hath sworn",9,19],["H1347","by the excellency",20,37],["H3290","of Jacob",38,46],["H5331","Surely I will never",48,67],["H7911","forget",68,74],["H4639","any of their works",75,93]]},"8:8":{"text":"Shall not the land tremble for this, and every one mourn that dwelleth therein? and it shall rise up wholly as a flood; and it shall be cast out and drowned, as by the flood of Egypt.","words":[["H0776","Shall not the land",0,18],["H7264","tremble",19,26],["H0056","for this, and every one mourn",27,56],["H3427","that dwelleth",57,70],["H5927","therein? and it shall rise up",71,100],["H2975","wholly as a flood",101,118],["H1644","and it shall be cast out",120,144],["H8257","and drowned",145,156],["H8248","and drowned",145,156],["H0216","as by the flood",158,173],["H4714","of Egypt",174,182]]},"8:9":{"text":"And it shall come to pass in that day, saith the Lord GOD, that I will cause the sun to go down at noon, and I will darken the earth in the clear day:","words":[["H3117","And it shall come to pass in that day",0,37],["H5002","saith",39,44],["H0136","the Lord",45,53],["H3069","GOD",54,57],["H8121","that I will cause the sun",59,84],["H0935","to go down",85,95],["H6672","at noon",96,103],["H2821","and I will darken",105,122],["H0776","the earth",123,132],["H0216","in the clear",133,145],["H3117","day",146,149]]},"8:10":{"text":"And I will turn your feasts into mourning, and all your songs into lamentation; and I will bring up sackcloth upon all loins, and baldness upon every head; and I will make it as the mourning of an only son, and the end thereof as a bitter day.","words":[["H2015","And I will turn",0,15],["H2282","your feasts",16,27],["H0060","into mourning",28,41],["H7892","and all your songs",43,61],["H7015","into lamentation",62,78],["H5927","and I will bring up",80,99],["H8242","sackcloth",100,109],["H4975","upon all loins",110,124],["H7144","and baldness",126,138],["H7218","upon every head",139,154],["H7760","and I will make",156,171],["H0060","it as the mourning",172,190],["H3173","of an only",191,201],["H0319","son, and the end",202,218],["H4751","thereof as a bitter",219,238],["H3117","day",239,242]]},"8:11":{"text":"Behold, the days come, saith the Lord GOD, that I will send a famine in the land, not a famine of bread, nor a thirst for water, but of hearing the words of the LORD:","words":[["H3117","Behold, the days",0,16],["H0935","come",17,21],["H5002","saith",23,28],["H0136","the Lord",29,37],["H3069","GOD",38,41],["H7971","that I will send",43,59],["H7458","a famine",60,68],["H0776","in the land",69,80],["H7458","not a famine",82,94],["H3899","of bread",95,103],["H6772","nor a thirst",105,117],["H4325","for water",118,127],["H8085","but of hearing",129,143],["H1697","the words",144,153],["H3068","of the LORD",154,165]]},"8:12":{"text":"And they shall wander from sea to sea, and from the north even to the east, they shall run to and fro to seek the word of the LORD, and shall not find it.","words":[["H5128","And they shall wander",0,21],["H3220","from sea",22,30],["H3220","to sea",31,37],["H6828","and from the north",39,57],["H4217","even to the east",58,74],["H7751","they shall run to and fro",76,101],["H1245","to seek",102,109],["H1697","the word",110,118],["H3068","of the LORD",119,130],["H4672","and shall not find",132,150]]},"8:13":{"text":"In that day shall the fair virgins and young men faint for thirst.","words":[["H3117","In that day",0,11],["H3303","shall the fair",12,26],["H1330","virgins",27,34],["H0970","and young men",35,48],["H5968","faint",49,54],["H6772","for thirst",55,65]]},"8:14":{"text":"They that swear by the sin of Samaria, and say, Thy god, O Dan, liveth; and, The manner of Beersheba liveth; even they shall fall, and never rise up again.","words":[["H7650","They that swear",0,15],["H0819","by the sin",16,26],["H8111","of Samaria",27,37],["H0559","and say",39,46],["H0430","Thy god",48,55],["H1835","O Dan",57,62],["H2416","liveth",64,70],["H1870","and, The manner",72,87],["H0884","of Beersheba",88,100],["H2416","liveth",101,107],["H5307","even they shall fall",109,129],["H6965","and never rise up",131,148]]},"9:1":{"text":"I saw the Lord standing upon the altar: and he said, Smite the lintel of the door, that the posts may shake: and cut them in the head, all of them; and I will slay the last of them with the sword: he that fleeth of them shall not flee away, and he that escapeth of them shall not be delivered.","words":[["H7200","I saw",0,5],["H0136","the Lord",6,14],["H5324","standing",15,23],["H4196","upon the altar",24,38],["H0559","and he said",40,51],["H5221","Smite",53,58],["H3730","the lintel of the door",59,81],["H5592","that the posts",83,97],["H7493","may shake",98,107],["H1214","and cut",109,116],["H7218","them in the head",117,133],["H2026","all of them; and I will slay",135,163],["H0319","the last",164,172],["H2719","of them with the sword",173,195],["H5127","he that fleeth",197,211],["H5127","of them shall not flee away",212,239],["H6412","and he that escapeth",241,261],["H4422","of them shall not be delivered",262,292]]},"9:2":{"text":"Though they dig into hell, thence shall mine hand take them; though they climb up to heaven, thence will I bring them down:","words":[["H2864","Though they dig",0,15],["H7585","into hell",16,25],["H3027","thence shall mine hand",27,49],["H3947","take",50,54],["H5927","them; though they climb up",55,81],["H8064","to heaven",82,91],["H3381","thence will I bring them down",93,122]]},"9:3":{"text":"And though they hide themselves in the top of Carmel, I will search and take them out thence; and though they be hid from my sight in the bottom of the sea, thence will I command the serpent, and he shall bite them:","words":[["H2244","And though they hide",0,20],["H7218","themselves in the top",21,42],["H3760","of Carmel",43,52],["H2664","I will search",54,67],["H3947","and take them out",68,85],["H5641","thence; and though they be hid",86,116],["H5869","from my sight",117,130],["H7172","in the bottom",131,144],["H3220","of the sea",145,155],["H6680","thence will I command",157,178],["H5175","the serpent",179,190],["H5391","and he shall bite",192,209]]},"9:4":{"text":"And though they go into captivity before their enemies, thence will I command the sword, and it shall slay them: and I will set mine eyes upon them for evil, and not for good.","words":[["H3212","And though they go",0,18],["H7628","into captivity",19,33],["H6440","before",34,40],["H0341","their enemies",41,54],["H6680","thence will I command",56,77],["H2719","the sword",78,87],["H2026","and it shall slay",89,106],["H7760","them: and I will set",107,127],["H5869","mine eyes",128,137],["H7451","upon them for evil",138,156],["H2896","and not for good",158,174]]},"9:5":{"text":"And the Lord GOD of hosts is he that toucheth the land, and it shall melt, and all that dwell therein shall mourn: and it shall rise up wholly like a flood; and shall be drowned, as by the flood of Egypt.","words":[["H0136","And the Lord",0,12],["H3069","GOD",13,16],["H6635","of hosts",17,25],["H5060","is he that toucheth",26,45],["H0776","the land",46,54],["H4127","and it shall melt",56,73],["H3427","and all that dwell",75,93],["H0056","therein shall mourn",94,113],["H5927","and it shall rise up",115,135],["H2975","wholly like a flood",136,155],["H8257","and shall be drowned",157,177],["H2975","as by the flood",179,194],["H4714","of Egypt",195,203]]},"9:6":{"text":"It is he that buildeth his stories in the heaven, and hath founded his troop in the earth; he that calleth for the waters of the sea, and poureth them out upon the face of the earth: The LORD is his name.","words":[["H1129","It is he that buildeth",0,22],["H4609","his stories",23,34],["H8064","in the heaven",35,48],["H3245","and hath founded",50,66],["H0092","his troop",67,76],["H0776","in the earth",77,89],["H7121","he that calleth",91,106],["H4325","for the waters",107,121],["H3220","of the sea",122,132],["H8210","and poureth them out",134,154],["H6440","upon the face",155,168],["H0776","of the earth",169,181],["H3068","The LORD",183,191],["H8034","is his name",192,203]]},"9:7":{"text":"Are ye not as children of the Ethiopians unto me, O children of Israel? saith the LORD. Have not I brought up Israel out of the land of Egypt? and the Philistines from Caphtor, and the Syrians from Kir?","words":[["H1121","Are ye not as children",0,22],["H3569","of the Ethiopians",23,40],["H1121","unto me, O children",41,60],["H3478","of Israel",61,70],["H5002","saith",72,77],["H3068","the LORD",78,86],["H5927","Have not I brought up",88,109],["H3478","Israel",110,116],["H0776","out of the land",117,132],["H4714","of Egypt",133,141],["H6430","and the Philistines",143,162],["H3731","from Caphtor",163,175],["H0758","and the Syrians",177,192],["H7024","from Kir",193,201]]},"9:8":{"text":"Behold, the eyes of the Lord GOD are upon the sinful kingdom, and I will destroy it from off the face of the earth; saving that I will not utterly destroy the house of Jacob, saith the LORD.","words":[["H5869","Behold, the eyes",0,16],["H0136","of the Lord",17,28],["H3069","GOD",29,32],["H2403","are upon the sinful",33,52],["H4467","kingdom",53,60],["H8045","and I will destroy",62,80],["H6440","it from off the face",81,101],["H0127","of the earth",102,114],["H0657","saving",116,122],["H8045","that I will not utterly",123,146],["H8045","destroy",147,154],["H1004","the house",155,164],["H3290","of Jacob",165,173],["H5002","saith",175,180],["H3068","the LORD",181,189]]},"9:9":{"text":"For, lo, I will command, and I will sift the house of Israel among all nations, like as corn is sifted in a sieve, yet shall not the least grain fall upon the earth.","words":[["H6680","For, lo, I will command",0,23],["H5128","and I will sift",25,40],["H1004","the house",41,50],["H3478","of Israel",51,60],["H1471","among all nations",61,78],["H5128","like as corn is sifted",80,102],["H3531","in a sieve",103,113],["H6872","yet shall not the least grain",115,144],["H5307","fall",145,149],["H0776","upon the earth",150,164]]},"9:10":{"text":"All the sinners of my people shall die by the sword, which say, The evil shall not overtake nor prevent us.","words":[["H2400","All the sinners",0,15],["H5971","of my people",16,28],["H4191","shall die",29,38],["H2719","by the sword",39,51],["H0559","which say",53,62],["H7451","The evil",64,72],["H5066","shall not overtake",73,91],["H6923","nor prevent",92,103]]},"9:11":{"text":"In that day will I raise up the tabernacle of David that is fallen, and close up the breaches thereof; and I will raise up his ruins, and I will build it as in the days of old:","words":[["H3117","In that day",0,11],["H6965","will I raise up",12,27],["H5521","the tabernacle",28,42],["H1732","of David",43,51],["H5307","that is fallen",52,66],["H1443","and close up",68,80],["H6556","the breaches",81,93],["H6965","thereof; and I will raise up",94,122],["H2034","his ruins",123,132],["H1129","and I will build",134,150],["H3117","it as in the days",151,168],["H5769","of old",169,175]]},"9:12":{"text":"That they may possess the remnant of Edom, and of all the heathen, which are called by my name, saith the LORD that doeth this.","words":[["H3423","That they may possess",0,21],["H7611","the remnant",22,33],["H0123","of Edom",34,41],["H1471","and of all the heathen",43,65],["H7121","which are called",67,83],["H8034","by my name",84,94],["H5002","saith",96,101],["H3068","the LORD",102,110],["H6213","that doeth",111,121]]},"9:13":{"text":"Behold, the days come, saith the LORD, that the plowman shall overtake the reaper, and the treader of grapes him that soweth seed; and the mountains shall drop sweet wine, and all the hills shall melt.","words":[["H3117","Behold, the days",0,16],["H0935","come",17,21],["H5002","saith",23,28],["H3068","the LORD",29,37],["H2790","that the plowman",39,55],["H5066","shall overtake",56,70],["H7114","the reaper",71,81],["H1869","and the treader",83,98],["H6025","of grapes",99,108],["H4900","him that soweth",109,124],["H2233","seed",125,129],["H2022","and the mountains",131,148],["H5197","shall drop",149,159],["H6071","sweet wine",160,170],["H1389","and all the hills",172,189],["H4127","shall melt",190,200]]},"9:14":{"text":"And I will bring again the captivity of my people of Israel, and they shall build the waste cities, and inhabit them; and they shall plant vineyards, and drink the wine thereof; they shall also make gardens, and eat the fruit of them.","words":[["H7725","And I will bring again",0,22],["H7622","the captivity",23,36],["H5971","of my people",37,49],["H3478","of Israel",50,59],["H1129","and they shall build",61,81],["H8074","the waste",82,91],["H5892","cities",92,98],["H3427","and inhabit",100,111],["H5193","them; and they shall plant",112,138],["H3754","vineyards",139,148],["H8354","and drink",150,159],["H3196","the wine",160,168],["H6213","thereof; they shall also make",169,198],["H1593","gardens",199,206],["H0398","and eat",208,215],["H6529","the fruit",216,225]]},"9:15":{"text":"And I will plant them upon their land, and they shall no more be pulled up out of their land which I have given them, saith the LORD thy God.","words":[["H5193","And I will plant",0,16],["H0127","them upon their land",17,37],["H5428","and they shall no more be pulled up",39,74],["H0127","out of their land",75,92],["H5414","which I have given",93,111],["H0559","them, saith",112,123],["H3068","the LORD",124,132],["H0430","thy God",133,140]]}}};
